#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(int x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
CI MAXN=1e5+5;
int n,k,a[MAXN],ansl[MAXN],ansr[MAXN];
int main(void){
    n=read(),k=read();
	for(int i=1;i<=n;++i)
    {
        a[i]=read();
    }
	sort(a+1,a+n+1);
	int l=1,r=n;
	for(int i=1;i<=n;++i)
    {
		while(a[i]-a[l]>k&&l<=i)
        {
            ++l;
        }
		ansl[i]=max(ansl[i-1],i-l+1);
	}
	for(int i=n;i>=1;--i)
    {
        while(a[r]-a[i]>k&&r>=i)
        {
            --r;
        }
		ansr[i]=max(ansr[i+1],r-i+1);
	}
	int ans=0;
	for(int i=1;i<n;++i)
	{
	    ans=max(ans,ansl[i]+ansr[i+1]);
    }
	write(ans);
	return false;
}
